112→interface DashboardVisualizationPanelProps {
113→  descriptor: PanelDescriptor;
114→  initialTimeSpan?: TimeSpan;
115→  initialFilterExpression?: string;
116→  initialLoading?: boolean;
117→  onCollapsedChange?: (isCollapsed: boolean) => void;
118→  onChartSelection?: (
