808→          <div className="flex items-center justify-center h-full w-full min-h-[100px] transition-opacity duration-150">
809→            <Skeleton className="w-full h-full [animation-duration:1s]" />
810→          </div>
811→        ) : (
812→          <div className="h-full w-full transition-opacity duration-150">
813→            {error ? (
814→              ErrorComponent({
