  1→import type { FormatName, ObjectFormatter } from "@/lib/formatter";
  2→import type React from "react";
  3→
  4→export type SelectorUI = {
  5→  type: string;
  6→  name: string;
  7→  fields: FilterSpec[];
  8→};
  9→
 10→export type FilterType = "select" | "date_time";
 11→
 12→export type FilterSpec = SelectorFilterSpec | DateTimeFilterSpec;
 13→
 14→/**
 15→ * Map comparator -> expression template.
 16→ *
 17→ * Supported placeholders (replaced by DashboardFilterComponent):
 18→ * - {name}        : converted column name (see nameConverter)
 19→ * - {value}       : single value as escaped SQL string literal (including quotes)
 20→ * - {values}      : comma-joined escaped SQL string literals (e.g. 'a','b')
 21→ * - {valuesArray} : ClickHouse array literal (e.g. ['a','b'])
 22→ */
 23→export type ExpressionTemplateMap = Partial<Record<string, string>>;
 24→
 25→export type FilterDataSource =
 26→  | {
 27→      type: "inline";
 28→      values: Array<{ label: string; value: string }>;
 29→    }
 30→  | {
 31→      type: "sql";
 32→      sql: string;
 33→    };
 34→
 35→export interface SelectorFilterSpec {
 36→  filterType: "select";
 37→  name: string;
 38→  displayText: string;
 39→  /**
 40→   * Data source for loading selector values.
 41→   * - If type is "inline", uses the provided values array directly.
 42→   * - If type is "sql", uses the SQL query template to fetch options from the backend.
 43→   *
 44→   * For SQL data sources, supported template params (replaced by DashboardFilterComponent):
 45→   * - {from:String}, {to:String}, {rounding:UInt32}, {seconds:UInt32}, {startTimestamp:UInt32}, {endTimestamp:UInt32}
 46→   *   (same behavior as SQLQueryBuilder time span replacement)
 47→   * - {filterExpression:String} -> combined expression from previous selectors (or "1=1" if empty)
 48→   * - {timeFilter:String} -> generated from the date_time filter spec (or default time column if missing)
 49→   *
 50→   * The query should return a single-column result set; the first column is used as the selector value.
 51→   */
 52→  datasource: FilterDataSource;
 53→
 54→  // If not given, all comparators are supported
 55→  // See ComparatorManager for supported comparators
 56→  supportedComparators?: string[];
 57→
 58→  // Default to true is missing
 59→  onPreviousFilters?: boolean;
 60→
 61→  // Callback to convert name to the name in the expression
 62→  nameConverter?: (name: string) => string;
 63→
 64→  /**
 65→   * Optional comparator -> expression template map.
 66→   * If set (and comparator matches), it overrides `QueryPattern.toQueryString()`.
 67→   *
 68→   * Useful for array columns, e.g.:
 69→   * - "=": "has({name}, {value})"
 70→   * - "in": "hasAny({name}, {valuesArray})"
 71→   */
 72→  expressionTemplate?: ExpressionTemplateMap;
 73→
 74→  /**
 75→   * Optional initial filter pattern to apply when the component mounts.
 76→   * If provided, this filter will be automatically applied on initialization.
 77→   *
 78→   * Example:
 79→   * - { comparator: "!=", values: ["QueryStart"] } for `type <> 'QueryStart'`
 80→   * - { comparator: "in", values: ["value1", "value2"] } for `type IN ('value1', 'value2')`
 81→   */
 82→  defaultPattern?: {
 83→    comparator: string;
 84→    values: string[];
 85→  };
 86→}
 87→
 88→export interface DateTimeFilterSpec {
 89→  filterType: "date_time";
 90→  alias: string;
 91→  displayText: string;
 92→  width?: number;
 93→  /**
 94→   * The column name to apply the selected time span to (e.g. "event_time")
 95→   */
 96→  timeColumn: string;
 97→  /**
 98→   * Default time span label used by TimeSpanSelector (e.g. "Last 15 Mins")
 99→   */
100→  defaultTimeSpan?: string;
101→}
102→
103→// SQL Query interface
104→export interface SQLQuery {
105→  sql: string;
106→  headers?: Record<string, string>;
107→  params?: Record<string, unknown>;
108→
109→  interval?: {
110→    startISO8601: string;
111→    endISO8601: string;
112→    step: number;
113→    bucketCount?: number;
114→  };
115→}
116→
117→// Query Response interface
118→export interface QueryResponse {
119→  startTimestamp: number;
120→  endTimestamp: number;
121→  interval: number;
122→  data: unknown[];
123→}
124→
125→// Title Option interface
126→export interface TitleOption {
127→  title: string;
128→  link?: string;
129→  description?: string;
130→
131→  // Default to center
132→  align?: "left" | "center" | "right";
133→
134→  // Default to true. If false, the title bar will not be rendered
135→  showTitle?: boolean;
136→
137→  // Whether to show the refresh button in the toolbar
138→  showRefreshButton?: boolean;
139→}
140→
141→// Field Option interface
142→export interface FieldOption {
143→  // The name of property that is used to access value from a given object
144→  // Optional when defining fieldOptions in a Map/Record (the key is used as the name)
145→  // Will be set automatically by the component from the key or server response
146→  name?: string;
147→  title?: string;
148→  width?: number;
149→  minWidth?: number;
150→  sortable?: boolean;
151→  resizable?: boolean;
152→  pinned?: boolean;
153→
154→  align?: "left" | "right" | "center";
155→
156→  format?: FormatName | ObjectFormatter;
157→  // Arguments to pass to the formatter function (only used when format is FormatName)
158→  formatArgs?: unknown[];
159→
160→  yAxis?: number;
161→  inverse?: boolean;
162→  chartType?: string;
163→  fill?: boolean;
164→
165→  // Action column support: render custom action buttons for each row
166→  renderAction?: (row: Record<string, unknown>, rowIndex: number) => React.ReactNode;
167→
168→  // Position in the table (for ordering) starting from 1. If not provided, columns will be shown in data order.
169→  // If negative, the column will be hidden from the table.
170→  position?: number;
171→}
172→
173→// Grid position for version 3+ dashboards (Grafana-style layout)
174→// x, y are optional for auto-positioning; if provided, use manual positioning
175→export interface GridPos {
176→  x?: number; // Column position (0-23), optional for auto-positioning
177→  y?: number; // Row position (0+), optional for auto-positioning
178→  w: number; // Width in columns (1-24)
179→  h: number; // Height in flexible row units (similar to ch-ui's rowSpan)
180→}
181→
182→// Panel Descriptor base interface
183→export interface PanelDescriptor {
184→  type: string; // "line" | "bar" | "area" | "pie" | "scatter" | "heatmap" | "table" | "transpose-table" | "stat" | "custom"
185→
186→  titleOption?: TitleOption;
187→
188→  // If not given, it defaults to false
189→  collapsed?: boolean;
190→
191→  // Legacy width property (version 1-2)
192→  // For version 3+, use gridPos instead
193→  width?: number;
194→
195→  // Table content height in viewport units (vh) - DEPRECATED for normal dashboards
196→  // This property is legacy and should NOT be used for regular dashboard panels.
197→  // Instead, use gridPos.h to control panel height - the table will automatically
198→  // scroll within its container.
199→  // Only use this for special cases like drilldown dialogs where explicit vh height is needed.
200→  height?: number;
201→
202→  // Grid position for version 3+ (Grafana-style layout)
203→  // Controls both panel container size and table scrolling behavior
204→  // gridPos.h determines the panel height - tables will scroll if content exceeds this
205→  // If provided, takes precedence over width
206→  gridPos?: GridPos;
207→
208→  datasource: SQLQuery;
209→
210→  /**
211→   * key - for table, the key is column name. If it's '_row', then a action column is added
212→   */
213→  drilldown?: Record<string, PanelDescriptor>;
214→}
