216→// Action Column interface
217→export interface ActionColumn {
218→  // Title for the action column header, default is 'Action'
219→  title?: string;
220→  // Alignment of the action title in column, default is 'center'
221→  align?: "left" | "right" | "center";
222→  // Render function for action buttons/cells
223→  renderAction: (row: Record<string, unknown>, rowIndex: number) => React.ReactNode;
224→  // Position in the table (for ordering) starting from 1, relative to data columns.
225→  // If not provided, action columns will be shown at the end of the table.
