229→// Miscellaneous options for table display
230→export interface MiscOption {
231→  // If true, display an index column as the first column (default: false)
232→  enableIndexColumn?: boolean;
233→  // If true, enable expandable rows with transposed detail view (default: false)
234→  enableShowRowDetail?: boolean;
