238→
239→// Table Descriptor interface
240→export interface TableDescriptor extends PanelDescriptor {
241→  type: "table";
242→
243→  // Field options as Map or Record, where key is the field name
244→  // If not provided, all fields from data will be shown with default options
245→  fieldOptions?: Map<string, FieldOption> | Record<string, FieldOption>;
246→
247→  // Action columns configuration (rendered as separate columns, typically at the end)
248→  actions?: ActionColumn[];
249→
250→  // Sorting configuration
251→  sortOption?: {
252→    // Initial sorting configuration
253→    initialSort?: {
254→      column: string;
255→      direction: "asc" | "desc";
256→    };
257→
258→    // Enable server-side sorting. When enabled, sorting will modify the SQL ORDER BY clause
259→    // and re-execute the query instead of sorting client-side
260→    serverSideSorting?: boolean;
261→  };
262→
263→  // Header configuration
264→  headOption?: {
265→    // If true, the table header will be sticky (fixed at top when scrolling)
266→    // Default to false
