268→  };
269→
270→  // Miscellaneous display options
271→  miscOption?: MiscOption;
272→
273→  /**
274→   * Pagination configuration.
275→   * Currently only server mode is supported by `DashboardPanelTable`.
276→   */
277→  pagination?: {
278→    mode: "server";
279→    pageSize: number;
280→  };
281→}
282→
283→// Transpose Table Descriptor interface
284→export interface TransposeTableDescriptor extends PanelDescriptor {
285→  type: "transpose-table";
286→
287→  // Field options as Map or Record, where key is the field name
288→  // The title property will be used to show the text in the name column
289→  // If not provided, all fields from data will be shown with default options
290→  fieldOptions?: Map<string, FieldOption> | Record<string, FieldOption>;
291→}
292→
293→// Reducer type for stat charts
294→export type Reducer = "min" | "max" | "avg" | "sum" | "count" | "first" | "last";
295→
296→/**
297→ * Apply a reducer function to an array of numbers
298→ * @param data - Array of numbers (may contain null/undefined values which will be filtered out)
299→ * @param reducer - The reducer type to apply
300→ * @returns The reduced value, or 0 if no valid data
301→ */
302→export function applyReducer(data: (number | null | undefined)[], reducer: Reducer): number {
303→  // Filter out null and undefined values
304→  const values = data.filter((v): v is number => v !== null && v !== undefined);
305→
306→  if (values.length === 0) {
307→    return 0;
308→  }
309→
310→  switch (reducer) {
311→    case "min":
312→      return Math.min(...values);
313→    case "max":
314→      return Math.max(...values);
315→    case "sum":
316→      return values.reduce((acc, val) => acc + val, 0);
317→    case "count":
318→      return values.length;
319→    case "first":
320→      return values[0];
321→    case "last":
322→      return values[values.length - 1];
323→    case "avg":
324→      return values.reduce((acc, val) => acc + val, 0) / values.length;
325→  }
326→}
327→
328→// Minimap Option type for stat charts
329→export type MinimapOption = {
330→  type: "line" | "area" | "none";
331→};
332→
333→// Stat Descriptor interface
334→export interface StatDescriptor extends PanelDescriptor {
335→  type: "stat";
336→
337→  // Minimap style for stat chart
338→  minimapOption?: MinimapOption;
339→
340→  comparisonOption?: {
341→    offset: string;
342→  };
343→
344→  // Value reducer option for stat chart
345→  valueOption?: {
346→    reducer?: Reducer;
347→
348→    // Style
349→    textSize?: number;
350→    textColor?: string;
351→
352→    // Default to center
353→    align?: "left" | "center" | "right";
354→
355→    format?: FormatName;
356→  };
357→}
358→
359→// Timeseries Descriptor interface
360→export interface TimeseriesDescriptor extends PanelDescriptor {
361→  type: "line" | "bar" | "area";
