300→
301→        // Prevent scroll event propagation from tooltip description to suggestion list
302→        // The CSS overscroll-behavior: contain should handle most cases,
303→        // but we also stop wheel event propagation as a backup
304→        const attachScrollPrevention = (element: HTMLElement) => {
305→          const preventPropagation = (e: WheelEvent) => {
306→            // Stop propagation in the bubble phase (after the scroll has happened)
307→            // This allows the scroll to work within the description div,
308→            // but prevents it from bubbling up to the suggestion list
