383→              }
384→            }
385→          },
386→        });
387→
388→        // When editor is ready, update the editor state
389→        const initialCursor = extendedEditor.getCursorPosition();
390→        updateQueryInputState({
391→          text: extendedEditor.getValue(),
392→          selectedText: "",
393→          cursorRow: initialCursor.row,
394→          cursorColumn: initialCursor.column,
395→        });
396→
397→        // Add command to toggle mode
398→        // editor.commands.addCommand({
399→        //   name: "toggleMode",
400→        //   bindKey: { win: "Ctrl-I", mac: "Command-I" },
401→        //   exec: () => {
