412→
413→    // Handle switching modes (storage key / language changes) without unmounting
414→    useEffect(() => {
415→      if (!editorRef.current) return;
416→
417→      // Load saved content for the new key
418→      const savedValue = QueryInputLocalStorage.getInput(storageKey);
