 21→type AutoRefreshProps = {
 22→  onRefresh: () => void;
 23→  size?: "default" | "sm" | "lg" | "icon";
 24→};
 25→
 26→const AutoRefresher: React.FC<AutoRefreshProps> = ({ onRefresh, size = "icon" }) => {
 27→  const [refreshInterval, setRefreshInterval] = useState<number | null>(null);
 28→  const [countDown, setCountDown] = useState(0);
 29→  const [isRunning, setIsRunning] = useState(false);
 30→  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 31→
 32→  useEffect(() => {
 33→    if (refreshInterval !== null) {
 34→      setCountDown(refreshInterval);
 35→      setIsRunning(true);
 36→
 37→      timerRef.current = setInterval(() => {
 38→        // The hook below on the countDown will trigger the refresh
 39→        setCountDown((prev) => prev - 1);
 40→      }, 1000);
 41→    }
 42→
 43→    return () => {
 44→      if (timerRef.current) {
 45→        clearInterval(timerRef.current);
 46→      }
 47→    };
 48→  }, [refreshInterval, onRefresh]);
 49→
 50→  const handleMenuItemClick = (interval: number) => {
 51→    if (timerRef.current) {
 52→      clearInterval(timerRef.current);
 53→    }
 54→    setRefreshInterval(interval);
 55→    setCountDown(interval);
 56→    setIsRunning(interval !== null);
 57→  };
 58→
 59→  useEffect(() => {
 60→    if (countDown <= 0 && isRunning) {
 61→      onRefresh();
 62→      setCountDown(refreshInterval!);
 63→    }
 64→  }, [countDown, isRunning, onRefresh, refreshInterval]);
 65→
 66→  const stopTimer = () => {
 67→    if (timerRef.current) {
 68→      clearInterval(timerRef.current);
 69→    }
 70→    setRefreshInterval(null);
 71→    setCountDown(0);
 72→    setIsRunning(false);
 73→  };
 74→
 75→  // For "sm" size, we need to make it square like icon but with sm height
 76→  // We'll use a custom className to override the size
 77→  const buttonSize = size === "sm" ? undefined : size;
 78→  const buttonClassName = cn(size === "sm" ? "h-8 w-8" : "", "rounded-none rounded-r");
 79→
 80→  return (
 81→    <DropdownMenu>
 82→      <DropdownMenuTrigger asChild>
 83→        <Button variant="outline" size={buttonSize} className={buttonClassName}>
 84→          {isRunning ? countDown + "s" : <ChevronDown className="h-4 w-4" />}
 85→        </Button>
 86→      </DropdownMenuTrigger>
 87→      <DropdownMenuContent className="w-12 rounded-none" align="end" side="bottom" sideOffset={0}>
 88→        <DropdownMenuItem className="cursor-pointer" onClick={stopTimer}>
 89→          Off
 90→        </DropdownMenuItem>
 91→        <DropdownMenuItem className="cursor-pointer" onClick={() => handleMenuItemClick(10)}>
 92→          10s
 93→        </DropdownMenuItem>
 94→        <DropdownMenuItem className="cursor-pointer" onClick={() => handleMenuItemClick(30)}>
 95→          30s
 96→        </DropdownMenuItem>
 97→        <DropdownMenuItem className="cursor-pointer" onClick={() => handleMenuItemClick(60)}>
 98→          60s
 99→        </DropdownMenuItem>
100→      </DropdownMenuContent>
101→    </DropdownMenu>
102→  );
103→};
