105→export interface TimeSpan {
106→  startISO8601: string;
107→  endISO8601: string;
108→}
109→
110→export class DisplayTimeSpan {
111→  label: string;
112→  value: number | "today" | "yesterday" | "all" | "user";
113→  unit?: string;
114→
115→  // When 'value' is 'user', these two are ISO8601 format strings
116→  start?: string;
117→  end?: string;
118→
119→  enabled: boolean;
120→
121→  // A runtime flag
122→  initial?: boolean;
123→
124→  // A runtime property to store the absolute time span
125→  absoluteTimeSpan?: TimeSpan;
126→
127→  constructor(
128→    label: string,
129→    value: number | "today" | "yesterday" | "all" | "user",
130→    unit: string,
131→    enabled: boolean,
132→    start?: string,
133→    end?: string
134→  ) {
135→    this.label = label;
136→    this.value = value;
137→    this.unit = unit;
138→    this.enabled = enabled;
139→    this.start = start;
140→    this.end = end;
141→  }
142→
143→  public isUserDefined(): boolean {
144→    return this.value === "user";
145→  }
146→
147→  public getURLParameterValue(): string {
148→    if (this.value === "user") {
149→      // For user, the label is not ISO8601 format
150→      // We use ISO8601 in the start and end variable as parameter values
151→      return `${this.start} - ${this.end}`;
152→    } else {
153→      return this.label;
154→    }
155→  }
156→
157→  public getTimeSpan(): TimeSpan {
158→    if (this.absoluteTimeSpan === undefined) {
159→      this.absoluteTimeSpan = this.calculateAbsoluteTimeSpan();
160→    }
161→    return this.absoluteTimeSpan;
162→  }
163→
164→  public reCalculateTimeSpan(): TimeSpan {
165→    this.absoluteTimeSpan = this.calculateAbsoluteTimeSpan();
166→    return this.absoluteTimeSpan;
167→  }
168→
169→  public calculateAbsoluteTimeSpan(): TimeSpan {
170→    const val = this.value;
171→    if (val === "today") {
172→      const e = new Date();
173→      const s = startOfDay(e);
174→      return {
175→        startISO8601: DateTimeExtension.formatISO8601(s) || "",
176→        endISO8601: DateTimeExtension.formatISO8601(e) || "",
177→      };
178→    } else if (val === "yesterday") {
179→      const e = startOfDay(new Date());
180→      const s = subDays(e, 1);
181→      return {
182→        startISO8601: DateTimeExtension.formatISO8601(s) || "",
183→        endISO8601: DateTimeExtension.formatISO8601(e) || "",
184→      };
185→    } else if (this.unit === "m") {
186→      const e = new Date();
187→      const s = sub(e, { minutes: this.value as number });
188→      return {
189→        startISO8601: DateTimeExtension.formatISO8601(s) || "",
190→        endISO8601: DateTimeExtension.formatISO8601(e) || "",
191→      };
192→    } else if (this.unit === "h") {
193→      const e = new Date();
194→      const s = sub(e, { hours: this.value as number });
195→      return {
196→        startISO8601: DateTimeExtension.formatISO8601(s) || "",
197→        endISO8601: DateTimeExtension.formatISO8601(e) || "",
198→      };
199→    } else if (this.unit === "d") {
200→      const e = new Date();
201→      const s = sub(e, { days: this.value as number });
202→      return {
203→        startISO8601: DateTimeExtension.formatISO8601(s) || "",
204→        endISO8601: DateTimeExtension.formatISO8601(e) || "",
205→      };
206→    } else if (this.value === "user") {
207→      return { startISO8601: this.start || "", endISO8601: this.end || "" };
208→    } else if (this.value === "all") {
209→      return {
210→        startISO8601: this.start || "",
211→        endISO8601: this.end || "",
212→      };
213→    }
214→    // Default fallback
215→    const e = new Date();
216→    const s = startOfDay(e);
217→    return {
218→      startISO8601: DateTimeExtension.formatISO8601(s) || "",
219→      endISO8601: DateTimeExtension.formatISO8601(e) || "",
220→    };
221→  }
222→}
