224→export const BUILT_IN_TIME_SPAN_LIST: DisplayTimeSpan[] = [
225→  new DisplayTimeSpan("Last 1 Mins", 1, "m", true),
226→  new DisplayTimeSpan("Last 5 Mins", 5, "m", true),
227→  new DisplayTimeSpan("Last 15 Mins", 15, "m", true),
228→  new DisplayTimeSpan("Last 30 Mins", 30, "m", true),
229→  new DisplayTimeSpan("Last 1 Hour", 1, "h", true),
230→  new DisplayTimeSpan("Last 3 Hour", 3, "h", true),
231→  new DisplayTimeSpan("Last 6 Hours", 6, "h", true),
232→  new DisplayTimeSpan("Last 12 Hours", 12, "h", true),
233→  new DisplayTimeSpan("Last 1 Days", 1, "d", true),
234→  new DisplayTimeSpan("Last 3 Days", 3, "d", true),
235→  new DisplayTimeSpan("Last 5 Days", 5, "d", true),
236→  new DisplayTimeSpan("Last 7 Days", 7, "d", true),
237→  new DisplayTimeSpan("Today", "today", "d", true),
238→  new DisplayTimeSpan("Yesterday", "yesterday", "d", true),
239→
240→  // Disabled by default
241→  new DisplayTimeSpan(
242→    "All",
243→    "all",
244→    "unit",
245→    false,
246→    "2000-01-01T00:00:00.000Z",
247→    "2099-12-31T23:59:59.000Z"
248→  ),
249→];
