251→export function getDisplayTimeSpanByLabel(label: string): DisplayTimeSpan {
252→  const index = BUILT_IN_TIME_SPAN_LIST.findIndex((span) => span.label === label);
253→  if (index >= 0) {
254→    return BUILT_IN_TIME_SPAN_LIST[index];
255→  }
256→
257→  // Try to parse it user defined interval in the format of "yyyy-MM-dd HH:mm:ss - yyyy-MM-dd HH:mm:ss"
258→  const parts = label.split(" - ");
259→  const start = parse(parts[0], "yyyy-MM-dd'T'HH:mm:ssXXX", new Date());
260→  const end = parse(parts[1], "yyyy-MM-dd'T'HH:mm:ssXXX", new Date());
261→
262→  if (isValid(start) && isValid(end)) {
263→    return new DisplayTimeSpan(
264→      `${DateTimeExtension.toYYYYMMddHHmmss(start)} - ${DateTimeExtension.toYYYYMMddHHmmss(end)}`,
265→      "user",
266→      "unit",
267→      true,
268→      DateTimeExtension.formatISO8601(start),
269→      DateTimeExtension.formatISO8601(end)
270→    );
271→  }
272→
273→  // Returns default time span in Last 15 Mins
274→  return BUILT_IN_TIME_SPAN_LIST[3];
275→}
