"use client";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Switch } from "@/components/ui/switch";
import { cn } from "@/lib/utils";
import { ChevronDown, ChevronRight } from "lucide-react";
import { memo, useCallback, useState } from "react";
import {
  CHART_TYPE_LABELS,
  WIDGET_TEMPLATES,
  type ChartType,
  type GaugeOptions,
  type PieOptions,
  type StatOptions,
  type TableOptions,
  type TimeseriesOptions,
  type WidgetTemplate,
} from "./use-panel-edit-state";

// --- Toggle Option Button ---
function ToggleOption({
  selected,
  onClick,
  children,
}: {
  selected: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      className={cn(
        "px-2.5 py-1 rounded-md border text-xs transition-colors",
        selected
          ? "bg-primary text-primary-foreground border-primary"
          : "hover:bg-muted/50"
      )}
      onClick={onClick}
    >
      {children}
    </button>
  );
}

// --- Collapsible Section ---
function Section({
  title,
  children,
  defaultOpen = true,
}: {
  title: string;
  children: React.ReactNode;
  defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border-b last:border-b-0">
      <button
        type="button"
        className="flex items-center gap-1.5 w-full px-3 py-2 text-xs font-medium text-muted-foreground uppercase tracking-wider hover:bg-muted/30 transition-colors"
        onClick={() => setOpen(!open)}
      >
        {open ? (
          <ChevronDown className="h-3 w-3" />
        ) : (
          <ChevronRight className="h-3 w-3" />
        )}
        {title}
      </button>
      {open && <div className="px-3 pb-3 space-y-3">{children}</div>}
    </div>
  );
}

// --- Select dropdown ---
function SimpleSelect({
  value,
  options,
  onChange,
}: {
  value: string;
  options: { value: string; label: string }[];
  onChange: (value: string) => void;
}) {
  return (
    <select
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="w-full h-8 rounded-md border bg-background px-2 text-xs"
    >
      {options.map((opt) => (
        <option key={opt.value} value={opt.value}>
          {opt.label}
        </option>
      ))}
    </select>
  );
}

// --- Main Sidebar Props ---
interface PanelEditSidebarProps {
  chartType: ChartType;
  onChartTypeChange: (type: ChartType) => void;
  gridW: number;
  gridH: number;
  onGridSizeChange: (w: number, h: number) => void;
  // Type-specific options
  statOptions: StatOptions;
  onStatOptionsChange: (partial: Partial<StatOptions>) => void;
  timeseriesOptions: TimeseriesOptions;
  onTimeseriesOptionsChange: (
    partial: Partial<TimeseriesOptions>
  ) => void;
  pieOptions: PieOptions;
  onPieOptionsChange: (partial: Partial<PieOptions>) => void;
  gaugeOptions: GaugeOptions;
  onGaugeOptionsChange: (partial: Partial<GaugeOptions>) => void;
  tableOptions: TableOptions;
  onTableOptionsChange: (partial: Partial<TableOptions>) => void;
  // Templates
  isNewPanel: boolean;
  onApplyTemplate: (template: WidgetTemplate) => void;
}

function PanelEditSidebarComponent({
  chartType,
  onChartTypeChange,
  gridW,
  gridH,
  onGridSizeChange,
  statOptions,
  onStatOptionsChange,
  timeseriesOptions,
  onTimeseriesOptionsChange,
  pieOptions,
  onPieOptionsChange,
  gaugeOptions,
  onGaugeOptionsChange,
  tableOptions,
  onTableOptionsChange,
  isNewPanel,
  onApplyTemplate,
}: PanelEditSidebarProps) {
  const [showTemplates, setShowTemplates] = useState(false);

  return (
    <div className="flex flex-col h-full">
      {/* Sidebar header */}
      <div className="flex items-center px-3 py-1.5 border-b bg-muted/30 shrink-0">
