301→        <Plus className="h-4 w-4" />
302→        Add Your First Panel
303→      </Button>
304→    </div>
305→  );
306→}
307→
308→/**
309→ * Overlay buttons that appear in the dashboard header for editing panels
310→ */
311→function PanelEditOverlay({
312→  panels,
313→  onEditPanel,
314→  onDeletePanel,
315→}: {
316→  panels: PanelDescriptor[];
317→  onEditPanel: (index: number) => void;
318→  onDeletePanel: (index: number) => void;
319→}) {
320→  if (panels.length === 0) return null;
321→
322→  return (
323→    <DropdownMenu>
324→      <DropdownMenuTrigger asChild>
325→        <Button variant="outline" size="sm" className="h-7 text-xs gap-1">
326→          <Edit2 className="h-3.5 w-3.5" />
327→          Edit Panels
328→        </Button>
329→      </DropdownMenuTrigger>
330→      <DropdownMenuContent align="end" className="w-64">
331→        {panels.map((panel, index) => (
332→          <DropdownMenuItem
333→            key={index}
334→            className="flex items-center justify-between"
335→            onSelect={(e) => e.preventDefault()}
336→          >
337→            <span className="text-sm truncate mr-2">
338→              {panel.titleOption?.title ?? `Panel ${index + 1}`}
339→            </span>
340→            <div className="flex items-center gap-1 shrink-0">
341→              <Button
342→                variant="ghost"
343→                size="icon"
344→                className="h-6 w-6"
345→                onClick={() => onEditPanel(index)}
346→              >
347→                <Pencil className="h-3 w-3" />
348→              </Button>
349→              <Button
350→                variant="ghost"
351→                size="icon"
352→                className="h-6 w-6 text-destructive hover:text-destructive"
353→                onClick={() => onDeletePanel(index)}
354→              >
355→                <Trash2 className="h-3 w-3" />
356→              </Button>
357→            </div>
358→          </DropdownMenuItem>
359→        ))}
360→      </DropdownMenuContent>
361→    </DropdownMenu>
362→  );
363→}
364→
365→/**
366→ * Check if an item is a DashboardGroup
367→ */
368→function isDashboardGroup(item: PanelDescriptor | DashboardGroup): item is DashboardGroup {
369→  return "charts" in item && Array.isArray((item as DashboardGroup).charts);
370→}
371→
372→/**
373→ * Flatten panels from dashboard config (handles groups)
374→ */
375→function flattenPanels(
